  1	/**
  2	 * Add components common between cluster-wise and appicaltion-wise card here
  3	 */
  4	
  5	import * as React from 'react';
  6	import {
  7	  ALL_APPS,
  8	  ALL_APPS_ITEM_ID,
  9	  GITOPS_OPERATOR_NAMESPACE,
 10	  LEAST_SECONDS_IN_PROMETHEUS,
 11	  DISCOVERED_APP_NS,
 12	  ReplicationType,
 13	  VolumeReplicationHealth,
 14	} from '@odf/mco/constants';
 15	import {
 16	  DRClusterAppsMap,
 17	  ProtectedAppsMap,
 18	  ApplicationObj,
 19	  ProtectedPVCData,
 20	} from '@odf/mco/types';
 21	import {
 22	  filterPVCDataUsingApp,
 23	  getVolumeReplicationHealth,
 24	} from '@odf/mco/utils';
 25	import {
 26	  ACMSubscriptionModel,
 27	  ArgoApplicationSetModel,
 28	  DRPlacementControlModel,
 29	  TypeaheadDropdown,
 30	} from '@odf/shared';
 31	import { getTimeDifferenceInSeconds } from '@odf/shared/details-page/datetime';
 32	import { useScheduler } from '@odf/shared/hooks';
 33	import { ResourceIcon } from '@odf/shared/resource-link/resource-link';
 34	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 35	import { t_global_color_status_danger_default as globalDanger100 } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_default';
 36	import { t_global_color_status_info_default as globalInfo100 } from '@patternfly/react-tokens/dist/js/t_global_color_status_info_default';
 37	import { t_global_color_status_warning_default as globalWarning100 } from '@patternfly/react-tokens/dist/js/t_global_color_status_warning_default';
 38	import { ChartDonut } from '@patternfly/react-charts';
 39	import {
 40	  MenuToggle,
 41	  MenuToggleElement,
 42	  Flex,
 43	  FlexItem,
 44	  Text,
 45	  TextVariants,
 46	  Select,
 47	  SelectOption,
 48	  SelectList,
 49	  SelectGroup,
 50	  Divider,
 51	} from '@patternfly/react-core';
 52	
 53	const NAMESPACE_NAME_SPLIT_CHAR = '%#%';
 54	
 55	const namespaceToModelMapping = (namespace: string) => {
 56	  if (namespace === DISCOVERED_APP_NS) {
 57	    return DRPlacementControlModel;
 58	  } else if (namespace === GITOPS_OPERATOR_NAMESPACE) {
 59	    return ArgoApplicationSetModel;
 60	  } else {
 61	    return ACMSubscriptionModel;
 62	  }
 63	};
 64	
 65	const colorScale = [
 66	  globalDanger100.value,
 67	  globalWarning100.value,
 68	  globalInfo100.value,
 69	];
 70	
 71	const getNSAndNameFromId = (itemId: string): string[] => {
 72	  if (itemId?.includes(NAMESPACE_NAME_SPLIT_CHAR)) {
 73	    return itemId.split(NAMESPACE_NAME_SPLIT_CHAR);
 74	  } else {
 75	    return [undefined, ALL_APPS];
 76	  }
 77	};
 78	
 79	export const StatusText: React.FC<StatusTextProps> = ({ children }) => {
 80	  return (
 81	    <Text className="mco-dashboard__statusText--size mco-dashboard__statusText--margin mco-dashboard__statusText--weight">
 82	      {children}
 83	    </Text>
 84	  );
 85	};
 86	
 87	export const VolumeSummarySection: React.FC<VolumeSummarySectionProps> = ({
 88	  protectedPVCData,
 89	  selectedApplication,
 90	}) => {
 91	  const { t } = useCustomTranslation();
 92	  const [summary, setSummary] = React.useState({
 93	    critical: 0,
 94	    warning: 0,
 95	    healthy: 0,
 96	  });
 97	
 98	  const updateSummary = React.useCallback(() => {
 99	    const volumeHealth = { critical: 0, warning: 0, healthy: 0 };
100	    protectedPVCData?.forEach((pvcData) => {
101	      const pvcLastSyncTime = pvcData?.lastSyncTime;
102	      // Only RDR(async) has volume replication
103	      const health =
104	        pvcData.replicationType === ReplicationType.ASYNC
105	          ? getVolumeReplicationHealth(
106	              !!pvcLastSyncTime
107	                ? getTimeDifferenceInSeconds(pvcLastSyncTime)
108	                : LEAST_SECONDS_IN_PROMETHEUS,
109	              pvcData?.schedulingInterval
110	            )[0]
111	          : VolumeReplicationHealth.HEALTHY;
112	      !!selectedApplication
113	        ? filterPVCDataUsingApp(pvcData, selectedApplication) &&
114	          volumeHealth[health]++
115	        : volumeHealth[health]++;
116	    });
117	    setSummary(volumeHealth);
118	  }, [selectedApplication, protectedPVCData, setSummary]);
119	
120	  useScheduler(updateSummary);
121	
122	  return (
123	    <div className="mco-dashboard__contentColumn">
124	      <Text component={TextVariants.h3}>{t('Volume replication health')}</Text>
125	      <div className="mco-cluster-app__donut-chart">
126	        <ChartDonut
127	          ariaDesc="Volume replication health"
128	          constrainToVisibleArea={true}
129	          data={[
130	            { x: 'Critical', y: summary.critical },
131	            { x: 'Warning', y: summary.warning },
132	            { x: 'Healthy', y: summary.healthy },
133	          ]}
134	          labels={({ datum }) => `${datum.x}: ${datum.y}`}
135	          legendData={[
136	            {
137	              name: `Critical: ${summary.critical}`,
138	              symbol: { fill: colorScale[0] },
139	            },
140	            {
141	              name: `Warning: ${summary.warning}`,
142	              symbol: { fill: colorScale[1] },
143	            },
144	            {
145	              name: `Healthy: ${summary.healthy}`,
146	              symbol: { fill: colorScale[2] },
147	            },
148	          ]}
149	          legendOrientation="vertical"
150	          legendPosition="right"
151	          padding={{
152	            bottom: 0,
153	            left: 0,
154	            right: 200,
155	            top: 0,
156	          }}
157	          subTitle={t('Volumes')}
158	          colorScale={colorScale}
159	          title={`${summary.critical + summary.warning + summary.healthy}`}
160	          width={350}
161	        />
162	      </div>
163	    </div>
164	  );
165	};
166	
167	const ClusterDropdown: React.FC<Partial<ClusterAppDropdownProps>> = ({
168	  clusterResources,
169	  clusterName,
170	  setCluster,
171	  setApplication,
172	  className,
173	}) => {
174	  const { t } = useCustomTranslation();
175	
176	  const options = React.useMemo(
177	    () =>
178	      Object.keys(clusterResources)?.map((cluster) => (
179	        <SelectOption key={cluster} value={cluster}>
180	          {cluster}
181	        </SelectOption>
182	      )),
183	    [clusterResources]
184	  );
185	
186	  React.useEffect(() => {
187	    if (!clusterName && !!options.length) {
188	      // initial selection or when current selection is cleared
189	      setCluster(options?.[0].props.value);
190	    }
191	  }, [options, clusterName, setCluster]);
192	
193	  const onSelect = (selection: string) => {
194	    if (selection !== '') {
195	      setCluster(selection);
196	      setApplication({
197	        namespace: undefined,
198	        name: ALL_APPS,
199	      });
200	    } else {
201	      setCluster(null);
202	    }
203	  };
204	
205	  return (
206	    <TypeaheadDropdown
207	      className={className}
208	      selectedValue={t('Cluster: {{clusterName}}', { clusterName })}
209	      onSelect={onSelect}
210	      items={options}
211	      placeholder={t('Select a cluster')}
212	    />
213	  );
214	};
215	
216	const AppDropdown: React.FC<Partial<ClusterAppDropdownProps>> = ({
217	  clusterResources,
218	  clusterName,
219	  application,
220	  setApplication,
221	  className,
222	}) => {
223	  const { t } = useCustomTranslation();
224	  const [isOpen, setIsOpen] = React.useState(false);
225	  const menuRef = React.useRef<HTMLDivElement>(null);
226	
227	  const { name, namespace } = application;
228	  const selected = !namespace
229	    ? ALL_APPS_ITEM_ID
230	    : `${namespace}${NAMESPACE_NAME_SPLIT_CHAR}${name}`;
231	
232	  const options: AppOptions = React.useMemo(
233	    () =>
234	      clusterResources[clusterName]?.protectedApps?.reduce(
235	        (acc, protectedApp) => {
236	          const appName = protectedApp?.appName;
237	          const appNs = protectedApp?.appNamespace;
238	          if (!acc.hasOwnProperty(appNs)) acc[appNs] = [appName];
239	          else acc[appNs].push(appName);
240	          return acc;
241	        },
242	        {}
243	      ) || {},
244	    [clusterResources, clusterName]
245	  );
246	
247	  const namespaces = Object.keys(options);
248	  const isDiscoveredAppsFound = namespaces.includes(DISCOVERED_APP_NS);
249	  const isManagedAppsFound = namespaces.includes(DISCOVERED_APP_NS)
250	    ? namespaces.length > 1
251	    : namespaces.length > 0;
252	
253	  const onToggleClick = () => {
254	    setIsOpen(!isOpen);
255	  };
256	
257	  const onSelect = (
258	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
259	    itemId: string
260	  ) => {
261	    const [itemNamespace, itemName] = getNSAndNameFromId(itemId);
262	    setApplication({ namespace: itemNamespace, name: itemName });
263	    setIsOpen(false);
264	  };
265	
266	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => {
267	    const [selectedNamespace, selectedName] = getNSAndNameFromId(selected);
268	
269	    return (
270	      <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen}>
271	        {t('Application:')}{' '}
272	        {!!selectedNamespace ? (
273	          <>
274	            <ResourceIcon
275	              resourceModel={namespaceToModelMapping(selectedNamespace)}
276	            />
277	            {selectedName}
278	          </>
279	        ) : (
280	          selectedName
281	        )}
282	      </MenuToggle>
283	    );
284	  };
285	
286	  return (
287	    // ToDo: Add a search provision for the application name dropdown
288	    <Select
289	      id="single-select-next"
290	      ref={menuRef}
291	      isOpen={isOpen}
292	      selected={selected}
293	      onSelect={onSelect}
294	      onOpenChange={(isOpenFlag) => setIsOpen(isOpenFlag)}
295	      toggle={toggle}
296	    >
297	      <div className={className}>
298	        <SelectGroup label="Applications">
299	          <SelectList>
300	            <SelectOption itemId={ALL_APPS_ITEM_ID}>{ALL_APPS}</SelectOption>
301	          </SelectList>
302	        </SelectGroup>
303	        <Divider />
304	        {isDiscoveredAppsFound && (
305	          // Discovered application group
306	          <>
307	            <SelectGroup label={t('Discovered applications')}>
308	              <SelectList>
309	                {options[DISCOVERED_APP_NS]?.map((appName: string) => (
310	                  <SelectOption
311	                    key={DISCOVERED_APP_NS + appName}
312	                    value={`${DISCOVERED_APP_NS}${NAMESPACE_NAME_SPLIT_CHAR}${appName}`}
313	                    icon={
314	                      <ResourceIcon resourceModel={DRPlacementControlModel} />
315	                    }
316	                  >
317	                    {appName}
318	                  </SelectOption>
319	                ))}
320	              </SelectList>
321	            </SelectGroup>
322	            <Divider />
323	          </>
324	        )}
325	        {isManagedAppsFound && (
326	          // Managed application group
327	          <SelectGroup label={t('Managed applications')}>
328	            {Object.keys(options)?.map(
329	              (appNS: string) =>
330	                appNS !== DISCOVERED_APP_NS && (
331	                  <SelectGroup
332	                    key={appNS}
333	                    label={t('Namespace: ') + `${appNS}`}
334	                  >
335	                    <SelectList>
336	                      {options[appNS]?.map((appName: string) => (
337	                        <SelectOption
338	                          key={appNS + appName}
339	                          value={`${appNS}${NAMESPACE_NAME_SPLIT_CHAR}${appName}`}
340	                          icon={
341	                            <ResourceIcon
342	                              resourceModel={namespaceToModelMapping(appNS)}
343	                            />
344	                          }
345	                        >
346	                          {appName}
347	                        </SelectOption>
348	                      ))}
349	                    </SelectList>
350	                  </SelectGroup>
351	                )
352	            )}
353	          </SelectGroup>
354	        )}
355	      </div>
356	    </Select>
357	  );
358	};
359	
360	export const ClusterAppDropdown: React.FC<ClusterAppDropdownProps> = ({
361	  clusterResources,
362	  clusterName,
363	  application,
364	  setCluster,
365	  setApplication,
366	}) => {
367	  return (
368	    <Flex direction={{ default: 'column', sm: 'row' }}>
369	      <FlexItem>
370	        <ClusterDropdown
371	          clusterResources={clusterResources}
372	          clusterName={clusterName}
373	          setCluster={setCluster}
374	          setApplication={setApplication}
375	          className="mco-cluster-app__dropdown--padding"
376	        />
377	      </FlexItem>
378	      <FlexItem>
379	        <AppDropdown
380	          clusterResources={clusterResources}
381	          clusterName={clusterName}
382	          application={application}
383	          setApplication={setApplication}
384	          className="mco-cluster-app__dropdownHeight"
385	        />
386	      </FlexItem>
387	    </Flex>
388	  );
389	};
390	
391	export const ProtectedPVCsSection: React.FC<ProtectedPVCsSectionProps> = ({
392	  protectedPVCData,
393	  selectedApplication,
394	}) => {
395	  const { t } = useCustomTranslation();
396	  const [protectedPVC, setProtectedPVC] = React.useState([0, 0]);
397	  const [protectedPVCsCount, pvcsWithIssueCount] = protectedPVC;
398	
399	  const updateProtectedPVC = React.useCallback(() => {
400	    const issueCount =
401	      protectedPVCData?.reduce((acc, protectedPVCItem) => {
402	        const pvcLastSyncTime = protectedPVCItem?.lastSyncTime;
403	        // Only RDR(async) has volume replication
404	        const replicationHealth =
405	          protectedPVCItem.replicationType === ReplicationType.ASYNC
406	            ? getVolumeReplicationHealth(
407	                !!pvcLastSyncTime
408	                  ? getTimeDifferenceInSeconds(pvcLastSyncTime)
409	                  : LEAST_SECONDS_IN_PROMETHEUS,
410	                protectedPVCItem?.schedulingInterval
411	              )[0]
412	            : VolumeReplicationHealth.HEALTHY;
413	        (!!selectedApplication
414	          ? !!filterPVCDataUsingApp(protectedPVCItem, selectedApplication) &&
415	            replicationHealth !== VolumeReplicationHealth.HEALTHY
416	          : replicationHealth !== VolumeReplicationHealth.HEALTHY) && acc++;
417	
418	        return acc;
419	      }, 0) || 0;
420	    setProtectedPVC([protectedPVCData?.length || 0, issueCount]);
421	  }, [selectedApplication, protectedPVCData, setProtectedPVC]);
422	
423	  useScheduler(updateProtectedPVC);
424	
425	  return (
426	    <div className="mco-dashboard__contentColumn">
427	      <Text component={TextVariants.h1}>{protectedPVCsCount}</Text>
428	      <StatusText>{t('Protected volumes')}</StatusText>
429	      <Text className="text-muted">
430	        {t('{{ pvcsWithIssueCount }} with issues', { pvcsWithIssueCount })}
431	      </Text>
432	    </div>
433	  );
434	};
435	
436	type ProtectedPVCsSectionProps = {
437	  protectedPVCData: ProtectedPVCData[];
438	  selectedApplication?: ProtectedAppsMap;
439	};
440	
441	type VolumeSummarySectionProps = {
442	  protectedPVCData: ProtectedPVCData[];
443	  selectedApplication?: ProtectedAppsMap;
444	};
445	
446	type ClusterAppDropdownProps = {
447	  clusterResources: DRClusterAppsMap;
448	  clusterName: string;
449	  application: {
450	    name: string;
451	    namespace: string;
452	  };
453	  setCluster: React.Dispatch<React.SetStateAction<string>>;
454	  setApplication: React.Dispatch<React.SetStateAction<ApplicationObj>>;
455	  className?: string;
456	};
457	
458	type AppOptions = {
459	  [namespace: string]: string[];
460	};
461	
462	type StatusTextProps = {
463	  children: React.ReactNode;
464	};

