216	const AppDropdown: React.FC<Partial<ClusterAppDropdownProps>> = ({
217	  clusterResources,
218	  clusterName,
219	  application,
220	  setApplication,
221	  className,
222	}) => {
223	  const { t } = useCustomTranslation();
224	  const [isOpen, setIsOpen] = React.useState(false);
225	  const menuRef = React.useRef<HTMLDivElement>(null);
226	
227	  const { name, namespace } = application;
228	  const selected = !namespace
229	    ? ALL_APPS_ITEM_ID
230	    : `${namespace}${NAMESPACE_NAME_SPLIT_CHAR}${name}`;
231	
232	  const options: AppOptions = React.useMemo(
233	    () =>
234	      clusterResources[clusterName]?.protectedApps?.reduce(
235	        (acc, protectedApp) => {
236	          const appName = protectedApp?.appName;
237	          const appNs = protectedApp?.appNamespace;
238	          if (!acc.hasOwnProperty(appNs)) acc[appNs] = [appName];
239	          else acc[appNs].push(appName);
240	          return acc;
241	        },
242	        {}
243	      ) || {},
244	    [clusterResources, clusterName]
245	  );
246	
247	  const namespaces = Object.keys(options);
248	  const isDiscoveredAppsFound = namespaces.includes(DISCOVERED_APP_NS);
249	  const isManagedAppsFound = namespaces.includes(DISCOVERED_APP_NS)
250	    ? namespaces.length > 1
251	    : namespaces.length > 0;
252	
253	  const onToggleClick = () => {
254	    setIsOpen(!isOpen);
255	  };
256	
257	  const onSelect = (
258	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
259	    itemId: string
260	  ) => {
261	    const [itemNamespace, itemName] = getNSAndNameFromId(itemId);
262	    setApplication({ namespace: itemNamespace, name: itemName });
263	    setIsOpen(false);
264	  };
265	
266	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => {
267	    const [selectedNamespace, selectedName] = getNSAndNameFromId(selected);
268	
269	    return (
270	      <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen}>
271	        {t('Application:')}{' '}
272	        {!!selectedNamespace ? (
273	          <>
274	            <ResourceIcon
275	              resourceModel={namespaceToModelMapping(selectedNamespace)}
276	            />
277	            {selectedName}
278	          </>
279	        ) : (
280	          selectedName
281	        )}
282	      </MenuToggle>
283	    );
284	  };
285	
286	  return (
287	    // ToDo: Add a search provision for the application name dropdown
288	    <Select
289	      id="single-select-next"
290	      ref={menuRef}
291	      isOpen={isOpen}
292	      selected={selected}
293	      onSelect={onSelect}
294	      onOpenChange={(isOpenFlag) => setIsOpen(isOpenFlag)}
295	      toggle={toggle}
296	    >
297	      <div className={className}>
298	        <SelectList>
299	          <SelectGroup label="Applications">
300	            <SelectOption itemId={ALL_APPS_ITEM_ID}>{ALL_APPS}</SelectOption>
301	          </SelectGroup>
302	          <Divider />
303	          {isDiscoveredAppsFound && (
304	            // Discovered application group
305	            <>
306	              <SelectGroup label={t('Discovered applications')}>
307	                {options[DISCOVERED_APP_NS]?.map((appName: string) => (
308	                  <SelectOption
309	                    key={DISCOVERED_APP_NS + appName}
310	                    value={`${DISCOVERED_APP_NS}${NAMESPACE_NAME_SPLIT_CHAR}${appName}`}
311	                    icon={
312	                      <ResourceIcon resourceModel={DRPlacementControlModel} />
313	                    }
314	                  >
315	                    {appName}
316	                  </SelectOption>
317	                ))}
318	              </SelectGroup>
319	              <Divider />
320	            </>
321	          )}
322	          {isManagedAppsFound && (
323	            // Managed application group
324	            <SelectGroup label={t('Managed applications')}>
325	              {Object.keys(options)?.map(
326	                (appNS: string) =>
327	                  appNS !== DISCOVERED_APP_NS && (
328	                    <SelectGroup
329	                      key={appNS}
330	                      label={t('Namespace: ') + `${appNS}`}
331	                    >
332	                      {options[appNS]?.map((appName: string) => (
333	                        <SelectOption
334	                          key={appNS + appName}
335	                          value={`${appNS}${NAMESPACE_NAME_SPLIT_CHAR}${appName}`}
336	                          icon={
337	                            <ResourceIcon
338	                              resourceModel={namespaceToModelMapping(appNS)}
339	                            />
340	                          }
341	                        >
342	                          {appName}
343	                        </SelectOption>
344	                      ))}
345	                    </SelectGroup>
346	                  )
347	              )}
348	            </SelectGroup>
349	          )}
350	        </SelectList>
351	      </div>
352	    </Select>
353	  );
354	};
